mapper.sql:
AND ff.feature_vector IS NOT NULL
AND ff.feature_provider = #{featureProvider}
AND ff.feature_model = #{featureModel}

    AND ff.feature_dim = #{featureDim}


    AND LENGTH(ff.feature_vector) = #{expectedBytes}

mapper.select:
SELECT ff.id, ff.file_id, ff.feature_vector, ff.feature_dim, ff.feature_model, ff.feature_provider, ff.feature_version, f.origin_file_name, f.size, f.content_type, f.category, f.file_url, f.thumbnail_url, f.thumbnail_object_name, f.width, f.height FROM file_feature ff INNER JOIN user_file uf ON ff.file_id = uf.file_id AND ff.user_id = uf.user_id INNER JOIN file f ON ff.file_id = f.file_id WHERE ff.user_id = #{userId} AND uf.is_deleted = 0 AND f.category = 'image'
AND EXISTS ( SELECT 1 FROM album_picture ap WHERE ap.file_id = f.file_id AND ap.user_id = #{userId} AND ap.album_id IN
#{albumId}
)
AND EXISTS ( SELECT 1 FROM picture_tag pt WHERE pt.file_id = f.file_id AND pt.tag_name IN
#{tagName}
)
AND f.width IS NOT NULL AND f.height IS NOT NULL
AND (f.width * f.height) >= #{sizeMinPixels}
AND (f.width * f.height) < #{sizeMaxPixels}
ORDER BY ff.id ASC
